<header class="app-page-head"><div><p class="eyebrow">Eigene Listen</p><h1>Sammlungen</h1><p>Filmabend, Reiseproviant oder der große Chips-Vergleich.</p></div></header><section class="collection-create"><form method="post" action="<?=u('/app/collections/create')?>" class="form-stack"><?=$csrf?><div class="form-grid"><label>Name<input type="text" name="name" maxlength="120" required></label><label>Beschreibung<input type="text" name="description" maxlength="600"></label></div><button class="button button-small" type="submit">Sammlung anlegen</button></form></section><?php if(!$collections):?><div class="empty-state"><h2>Noch keine Sammlung.</h2><p>Lege oben deine erste private Liste an.</p></div><?php else:?><div class="collection-grid"><?php foreach($collections as $collection):?><a class="collection-card" href="<?=u('/app/collections/'.(int)$collection['id'])?>"><span class="collection-count"><?=e($collection['item_count'])?></span><p class="eyebrow">Private Sammlung</p><h2><?=e($collection['name'])?></h2><p><?=e($collection['description']?:'Noch ohne Beschreibung.')?></p></a><?php endforeach;?></div><?php endif;?>
